import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.Wufm-cgV.js";const u=JSON.parse('{"title":"Architecture","description":"How WebRouter works under the hood","frontmatter":{"title":"Architecture","description":"How WebRouter works under the hood"},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),r={name:"guide/architecture.md"};function o(i,e,l,p,c,d){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="component-overview" tabindex="-1">Component Overview <a class="header-anchor" href="#component-overview" aria-label="Permalink to &quot;Component Overview&quot;">​</a></h2><p>WebRouter consists of two main components that work together:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────┐     HTTP      ┌─────────────────┐</span></span>
<span class="line"><span>│   Browser   │ ───────────→ │    WebRouter     │</span></span>
<span class="line"><span>│   / CLI     │ ←──────────── │    (Flask)       │</span></span>
<span class="line"><span>└─────────────┘               │    :5050         │</span></span>
<span class="line"><span>                              └──────┬──────────┘</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                              ┌──────▼──────┐</span></span>
<span class="line"><span>                              │  wr-proxy    │</span></span>
<span class="line"><span>                              │  (Go) :5051  │</span></span>
<span class="line"><span>                              └──────┬──────┘</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                     ┌───────────────┼───────────────┐</span></span>
<span class="line"><span>                     │               │               │</span></span>
<span class="line"><span>              ┌──────▼──────┐ ┌──────▼──────┐ ┌──────▼──────┐</span></span>
<span class="line"><span>              │   direct    │ │  aggregate  │ │   custom    │</span></span>
<span class="line"><span>              │  (Official) │ │ (Aggregator)│ │ (Any OpenAI)│</span></span>
<span class="line"><span>              └─────────────┘ └─────────────┘ └─────────────┘</span></span></code></pre></div><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><h3 id="webrouter-flask-backend" tabindex="-1">WebRouter (Flask Backend) <a class="header-anchor" href="#webrouter-flask-backend" aria-label="Permalink to &quot;WebRouter (Flask Backend)&quot;">​</a></h3><p>The admin panel and REST API server:</p><ul><li><strong>Port:</strong> 5050</li><li><strong>Language:</strong> Python (Flask)</li><li><strong>Responsibilities:</strong> Provider management, token management, health monitoring, billing, team management, settings</li><li><strong>Database:</strong> SQLite (default) or MySQL/PostgreSQL</li><li><strong>Scheduler:</strong> APScheduler for periodic health checks and alert evaluation</li></ul><h3 id="wr-proxy-go-proxy-gateway" tabindex="-1">wr-proxy (Go Proxy Gateway) <a class="header-anchor" href="#wr-proxy-go-proxy-gateway" aria-label="Permalink to &quot;wr-proxy (Go Proxy Gateway)&quot;">​</a></h3><p>The high-performance request proxy:</p><ul><li><strong>Port:</strong> 5051</li><li><strong>Language:</strong> Go 1.22</li><li><strong>Responsibilities:</strong> Request forwarding, smart routing, retry with backoff, privacy desensitization, streaming, cost metering</li><li><strong>Database:</strong> Shares the same SQLite database as the Flask backend</li></ul><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><ol><li><strong>Client sends request</strong> to wr-proxy (<code>:5051/v1/chat/completions</code>) with a WebRouter API key</li><li><strong>wr-proxy authenticates</strong> the token and selects the best provider based on the model or <code>auto</code> routing</li><li><strong>Desensitization</strong> strips PII from the request body</li><li><strong>Forward</strong> the request to the upstream provider</li><li><strong>Meter</strong> token usage and cost</li><li><strong>Return</strong> the response to the client, re-sensitizing if needed</li></ol><h2 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h2><p>Both components share the same SQLite database file, allowing wr-proxy to read provider/token configuration and write request logs without needing a separate API layer.</p><h2 id="scheduler" tabindex="-1">Scheduler <a class="header-anchor" href="#scheduler" aria-label="Permalink to &quot;Scheduler&quot;">​</a></h2><p>The Flask backend runs two periodic tasks via APScheduler:</p><table tabindex="0"><thead><tr><th>Task</th><th>Interval</th><th>Description</th></tr></thead><tbody><tr><td>Health Check</td><td>5 minutes</td><td>Pings all providers and records latency/status</td></tr><tr><td>Alert Evaluation</td><td>1 minute</td><td>Evaluates alert rules against recent health data</td></tr></tbody></table>`,18)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
